#pragma once
#include <format>
#include <iostream>
#include <sstream>
#include <concepts>
#include <iterator>
#include <type_traits>


namespace hbstringable {
    template<typename T>
    concept Iterable = requires(T x) {
        std::begin(x);
        std::end(x);
    };

    template<typename T>
    concept formattable = requires(T &v, std::format_context ctx) {
        std::formatter<std::remove_cvref_t<T>>().format(v, ctx);
    };
};// namespace hbstringable

template<typename T>
constexpr auto harbour_stringify_type(const std::string &name, T v) noexcept -> std::string {
    std::string s;
    if constexpr (hbstringable::Iterable<T> && !std::convertible_to<T, std::string>) {
        s += std::format("{}: [ ", name);
        for (auto vv: v) {
            if constexpr (hbstringable::formattable<decltype(vv)>) {
                s += std::format("{} ", vv);
            } else {
                s += "nil ";
            }
        }
        s += "]";
    } else {
        if constexpr (hbstringable::formattable<T>) {
            s += std::format("{}: {}", name, v);
        } else {
            s += std::format("{}: nil", name);
        }
    }

    return s;
}

struct Stringable {
    constexpr auto string() noexcept -> std::string;
};

template<>
struct std::formatter<Stringable> {
    template<class ParseContext>
    constexpr auto parse(ParseContext &ctx) -> ParseContext::iterator {
        return ctx.begin();
    }

    template<class FmtContext>
    auto format(Stringable s, FmtContext &ctx) const -> FmtContext::iterator {
        return std::ranges::copy(s.string(), ctx.out()).out;
    }
};

// Allow a STRINGABLE struct to be printable with std::format
#define HARBOUR_FORMATTABLE(Type)                                            \
    template<>                                                               \
    struct std::formatter<Type> : std::formatter<Stringable> {               \
        template<class FmtContext>                                           \
        auto format(Type t, FmtContext &ctx) const -> FmtContext::iterator { \
            return std::ranges::copy(t.string(), ctx.out()).out;             \
        }                                                                    \
    };

